class BIT:
    __slots__ = ('n','tree')
    def __init__(self, n):
        self.n = n
        self.tree = [0]*(n+2)
    def add(self, i, delta):
        while i <= self.n:
            self.tree[i] += delta
            i += i & -i
    def sum(self, i):
        res = 0
        while i > 0:
            res += self.tree[i]
            i -= i & -i
        return res

class BIT:
    def __init__(self, n):
        self.n = n
        self.tree = [0]*n
    def add(self, i, delta):
        while i < self.n:
            self.tree[i] += delta
            i += 1
    def sum(self, i):
        return sum(self.tree[:i])

